тЅЇжаЁсЂ«уб║УфЇсЂЋсЂѕТИѕсѓЂсЂ░сђЂсЂѓсЂесЂ»packerсЂФсЂіжАўсЂёсЂЎсѓІсЂасЂЉсЂДсђїсЂѓсЂБРЮЌсђЇсЂеУеђсЂєжќЊсЂФухѓсѓЈсѓісЂЙсЂЎ­Ъўє extensions/init.luaсЂФС╗ЦСИІсѓњУ┐йУеўсЂЌсЂЙсЂЌсѓЄсЂєсђѓ extensions/init.lua require('packer').startup { function() use 'wbthomason/packer.nvim' -- тЅЇу»ђсЂДтЁЦсѓїсЂЪpackerсЂетљїтѕЌсЂФСИдсЂ╣сѓІ use 'nvim-treesitter/nvim-treesitter'
end,
-- (С╗ЦСИІуЋЦ) сЂДсђЂ:PackerSyncсѓњт«ЪУАїсЂЌсЂЙсЂЌсѓЄсЂєРЮЌ у░АтЇўсЂДсЂЎсЂГ­ЪўЅ сЂЎсЂБсЂћсЂёУдІсЂФсЂЈсЂёсЂЉсЂЕРЮЌ Note nvim-treesitterсЂ«УфгТўјсЂДсЂ»сђЂ:TSUpdateсѓњСйхсЂЏсЂдУАїсЂєсѓѕсЂєсЂФУфгТўјсЂЋсѓїсЂдсЂёсѓІсЂ«сЂДсЂЎсЂїсђЂсЂЊсѓїсЂ»сЂѓсЂЈсЂЙсЂДvim-plugсѓњСй┐ућесЂЌсЂдсЂёсѓІта┤тљѕсЂ«СЙІсЂДсЂЎсђѓ packer.nvimсЂДсЂ»runсѓфсЃЌсѓисЃДсЃ│сЂДтљїсЂўсЂЊсЂесЂїсЂДсЂЇсЂЮсЂєсЂфсѓЊсЂДсЂЎсЂїсђЂсЂЊсѓїсѓњСй┐ућесЂЎсѓІсЂетѕЮтЏъсЂасЂЉсѓесЃЕсЃ╝сЂїУхисЂЇсЂдсЂЌсЂЙсЂєсЂ«сЂДсђЂсѓЈсЂЪсЂЌсЂ»тцќсЂЌсЂдсЂёсЂЙсЂЎсђѓ сѓцсЃ│сѓ╣сЃѕсЃ╝сЃФУЄфСйЊсЂ»100%сЂДdone.сЂБсЂдсЂфсЂБсЂдсѓІсЂЌсђЂ2тЏъуЏ«С╗ЦжЎЇсЂ»СйЋС║ІсѓѓсЂфсЂІсЂБсЂЪсЂІсЂ«сѓѕсЂєсЂФ:TSUpdateсЂЙсЂДт«їУх░сЂДсЂЇсѓІсѓЊсЂДсЂЎсЂЉсЂЕсЂГсђѓсЂЎсЂБсЂћсЂёУдІсЂФсЂЈсЂёсЂЉсЂЕРЮЌ тѕЮтЏъсЂасЂЉтцќсЂЎсЂІсђЂсѓѓсЂЌсЂЈсЂ»Т░ЌсЂФсЂЌсЂфсЂёсЂІсЂЎсѓІсЂ«сЂДсЂѓсѓїсЂ░УХЁСЙ┐тѕЕсЂДсЂЎсђѓ use { 'nvim-treesitter/nvim-treesitter', run = ':TSUpdate', }

