сѓѓсЂєТёЈтю░сЂДсѓѓУЂќтцю­ЪїЃсЂФжќЊсЂФтљѕсѓЈсЂЏсЂЙсЂЎсђѓgitsignsсЂФУ▓асЂЉсЂфсЂёсЂЈсѓЅсЂёУХЁжФўжђЪсЂДсЂёсЂЇсЂЙсЂЌсѓЄсЂє­Ъўє С╗ітЏъсЂ»УЅ▓сђЁсѓФсѓ╣сѓ┐сЃъсѓцсѓ║сЂЌсЂдсЂёсЂЇсЂЪсЂёсЂ«сЂДсђЂ сЂЙсЂџсЂ» Usage сЂФуц║сЂЋсѓїсЂдсЂёсѓІсЃЄсЃЋсѓЕсЃФсЃѕсѓ╗сЃЃсЃєсѓБсЃ│сѓ░сѓњтЁЦсѓїсЂдсЂісЂЈсЂЊсЂесЂФсЂЌсЂЙсЂЌсѓЄсЂєсђѓ сЂЊсѓїсѓњтЪ║сЂФсђЂсЂѓсЂесЂДсѓФсѓ╣сѓ┐сЃъсѓцсѓ║сЂЌсЂдсЂёсЂЇсЂЙсЂЎсђѓ extensions/gitsigns.lua require('gitsigns').setup { signs = { add = { text = 'РћЃ' }, change = { text = 'РћЃ' }, delete = { text = '_' }, topdelete = { text = 'РђЙ' }, changedelete = { text = '~' }, untracked = { text = 'Рћє' }, }, signs_staged = { add = { text = 'РћЃ' }, change = { text = 'РћЃ' }, delete = { text = '_' }, topdelete = { text = 'РђЙ' }, changedelete = { text = '~' }, untracked = { text = 'Рћє' }, }, signs_staged_enable = true, signcolumn = true, -- Toggle with `:Gitsigns toggle_signs` numhl = false, -- Toggle with `:Gitsigns toggle_numhl` linehl = false, -- Toggle with `:Gitsigns toggle_linehl` word_diff = false, -- Toggle with `:Gitsigns toggle_word_diff` watch_gitdir = { follow_files = true }, auto_attach = true, attach_to_untracked = false, current_line_blame = false, -- Toggle with `:Gitsigns toggle_current_line_blame` current_line_blame_opts = { virt_text = true, virt_text_pos = 'eol', -- 'eol' | 'overlay' | 'right_align' delay = 1000, ignore_whitespace = false, virt_text_priority = 100, }, current_line_blame_formatter = '<author>, <author_time:%R> - <summary>', sign_priority = 6, update_debounce = 100, status_formatter = nil, -- Use default max_file_length = 40000, -- Disable if file is longer than this (in lines) preview_config = { -- Options passed to nvim_open_win border = 'single', style = 'minimal', relative = 'cursor', row = 0, col = 1 },
} extensions/init.lua use { 'lewis6991/gitsigns.nvim', config = function() require 'extensions.gitsigns' end,
} сЂБсЂдсЂЊсЂесЂДсђЂсѓѓсЂєсЂЎсЂБсЂІсѓісЂіжд┤ТЪЊсЂ┐сЂ«:PackerSync­Ъўє сѓѓсЂЌgitсЂ«у«АуљєСИІсЂФт▒ЁсЂЪсЂ«сЂфсѓЅсђЂсѓѓсЂєсЂЊсЂ«ТЎѓуѓ╣сЂДsigincolumnсЂФУБЁжБЙ­ЪјёсЂїсЂЋсѓїсЂдсЂЙсЂЎсЂГРЮЌyeah!! ­ЪЇЙ Note сЃЋсЃЕсѓцсЃ│сѓ░сЂДуЎ╗та┤сЂЌсЂдсЂёсЂЪ signcolumn сЂІсѓЅсЂЊсЂЊсЂЙсЂДсЂФ2сЃХТюѕсЂІсЂІсѓісЂЙсЂЌсЂЪ...сђѓ сЂЙсЂѓсЂфсѓЊсЂІсђЂсѓёсЂБсЂдсѓёсЂБсЂЪсЂюсЂБсЂдсЂфТёЪсЂўсЂ»сЂѓсѓісЂЙсЂЎРў║№ИЈ

