vim.api.nvim_set_var('loaded_netrwPlugin', 1) сЂДсђЂсЂёсЂцсѓѓсЂ«сЃЉсѓ┐сЃ╝сЃ│сђѓ extensions/nvim-tree.lua require('nvim-tree').setup { -- сЂЙсЂџсЂ»сЂІсѓЅсЂБсЂйсђю
} vim.api.nvim_create_user_command('Ex', function() vim.cmd.NvimTreeToggle() end, {}) extensions/init.lua use { 'nvim-tree/nvim-tree.lua', config = function() require 'extensions.nvim-tree' end, requires = 'nvim-tree/nvim-web-devicons', } сЂЮсЂЌсЂЪсѓЅсђЂсѓ│сЃъсЃ│сЃЅ:Exсѓњт«ЪУАїсЂЌсЂдсЂ┐сЂЙсЂЌсѓЄсЂєсђѓ сЂєсѓЊсђЂтЄ║сЂЙсЂЌсЂЪсЂГРў║№ИЈ у╣░сѓіУ┐ћсЂЌсЂФсЂфсѓісЂЙсЂЎсЂїсђЂExсѓ│сЃъсЃ│сЃЅсЂ»ТюгТЮЦnetrwсЂ«сѓ│сЃъсЃ│сЃЅсЂДсЂЎсђѓ сЂфсѓЊсЂДсЂЎсЂїРЮЌ уёАті╣тїќсЂЌсЂЪсЂ«сЂДС╣ЌсЂБтЈќсЂБсЂдсѓёсѓЇсЂєсЂБсЂдсЂёсЂєжГѓУЃєсЂДсЂЎсЂГ­Ъў╝ сЂЊсЂЊсЂДСИЇТёЈсѓњуфЂсЂёсЂдуЈЙсѓїсЂЪnvim_create_user_commandсЂФсЂцсЂёсЂдсЂ»14.4у»ђсЂФсЂдсђЂт«ЪсЂ»сЂЌсѓїсЂБсЂеУДдсѓїсЂдсЂЙсЂЌсЂЪ­Ъўє 14.4 Call The Plugin сѓѓсЂєСИђтђІсЂасЂЉсѓёсЂБсЂдсЂісЂЇсЂЪсЂёсЂ«сЂ»сђЂуІгУЄфсѓ│сЃъсЃ│сЃЅсЂІсѓЅсЃЌсЃЕсѓ░сѓцсЃ│сѓњСй┐сЂєсЃЉсѓ┐сЃ╝сЃ│сЂДсЂЎсђѓ сЂфсѓЊсЂеС╗ітЏъсђЂтИ░сЂБсЂдсЂЈсѓІсЂ«сЂ» Captain Marvel сЂасЂЉсЂДсЂ»сЂфсЂІсЂБсЂЪсЂ«сЂДсЂЎРЮЌсЂісЂІсЂѕсѓі­ЪцЌ Tip тєЇС╝џсЂФТ░┤сѓњти«сЂЎсѓѕсЂєсЂДсЂЎсЂїсђЂсѓЈсЂќсѓЈсЂќсѓ│сЃъсЃ│сЃЅТЅЊсЂцсЂ«сЂ»сѓЂсѓЊсЂЕсЂЈсЂЋсЂёсѓѕсЃ╝сЂБсЂдта┤тљѕсЂ»сЂёсЂцсѓѓжђџсѓісѓГсЃ╝сЃъсЃЃсЃЌсѓњСй┐сЂєсЂЊсЂесѓѓсђЂсѓѓсЂАсѓЇсѓЊтЈ»УЃйсЂДсЂЎсђѓ vim.keymap.set('n', '<leader>ex', vim.cmd.NvimTreeToggle) ...сЂ┐сЂЪсЂёсЂфРЮЊ сЂфсѓЊсЂасЂБсЂЪсѓЅтѕЦсЂФСИАТќ╣тЁЦсѓїсЂАсѓЃсЂБсЂдсѓѓсЂёсЂёсЂЌ ­Ъдє­Ъдє СИісЂ«СЙІсЂДсЂ»NvimTreeToggleсЂасЂЉсѓњСй┐ућесЂЌсЂдсЂёсЂЙсЂЎсЂїсђЂNvimTreeсЂ«жќІсЂЇТќ╣ (сЂесђЂжќЅсЂўТќ╣) сЂ»сЂёсЂЈсЂцсЂІсЂѓсѓісЂЙсЂЎ­Ъўї :h nvim-tree-commands 3. COMMANDS *nvim-tree-commands* :NvimTreeOpen opens the tree. Takes an optional path argument. сЃёсЃфсЃ╝сѓњжќІсЂЈсђѓсѓфсЃЌсѓисЃДсЃ│сЂ«pathт╝ЋТЋ░сѓњтЈќсѓісЂЙсЂЎсђѓ :NvimTreeClose closes the tree сЃёсЃфсЃ╝сѓњжќЅсЂўсЂЙсЂЎсђѓ :NvimTreeToggle open or close the tree. Takes an optional path argument. сЃёсЃфсЃ╝сѓњжќІсЂЈсђЂсЂЙсЂЪсЂ»жќЅсЂўсЂЙсЂЎсђѓсѓфсЃЌсѓисЃДсЃ│сЂ«pathт╝ЋТЋ░сѓњтЈќсѓісЂЙсЂЎсђѓ :NvimTreeFocus open the tree if it is closed, and then focus on the tree сЃёсЃфсЃ╝сЂїжќЅсЂўсЂдсЂёсѓІта┤тљѕсЂ»жќІсЂЇсђЂсЃёсЃфсЃ╝сЂФсЃЋсѓЕсЃ╝сѓФсѓ╣сЂЌсЂЙсЂЎсђѓ сѓѓсЂЌсѓѓсЂєт░ЉсЂЌу┤░сЂІсЂЈтѕХтЙАсЂЌсЂЪсЂёсЂеТђЮсЂБсЂЪсѓЅсђЂсЂЊсЂ«УЙ║сѓісѓњСй┐ућесЂЎсѓїсЂ░УЅ»сЂёсЂ»сЂџсЂДсЂЎ­ЪўЅ сЂЮсѓісѓЃсЂЮсЂєсЂасЂеУеђсѓЈсѓїсЂдсЂЌсЂЙсЂёсЂЮсЂєсЂДсЂЎсЂїсђЂжќЅсЂўсѓІсЂесЂЇсЂ»:qсѓё:bdсЂфсѓЊсЂІсЂДсѓѓсЂёсЂЉсЂЙсЂЎсђѓ

