end Nvim 0.10 local function createTreeActions() vim.iter(command):map(function(x) table.insert(menuCommand, { handler = x[2], name = x[3] }) end)
end Уф░сѓѓсЂїсђїсЂфсѓЊсѓёсЂЊсЂёсЂц­Ъў«сђЇсЂеТђЮсЂБсЂдсЂёсЂЪ_сЂїсЂёсЂфсЂЈсЂфсѓісЂЙсЂЌсЂЪсђѓ on_attach Nvim 0.9 function M.on_attach(bufnr) local opts = function(desc) return { desc = 'nvim-tree: ' .. desc, buffer = bufnr, nowait = true } end for _, cmd in pairs(command) do if (string.len(cmd[1]) > 0) then vim.keymap.set('n', cmd[1], cmd[2], opts(cmd[3])) end end
end Nvim 0.10 function M.on_attach(bufnr) local opts = function(desc) return { desc = 'nvim-tree: ' .. desc, buffer = bufnr, nowait = true } end vim .iter(command) :filter(function(x) return string.len(x[1]) > 0 end) :map(function(x) vim.keymap.set('n', x[1], x[2], opts(x[3])) end)
end СИісЂ«СЙІсЂ»StyluaсЂФу┤ауЏ┤сЂФтЙЊсЂБсЂдсЂёсѓІсЂ«сЂДсЂЎсЂїсђЂ сѓЈсЂЪсЂЌсЂ»сЂЊсЂ«Тћ╣УАїСйЇуй«сЂФсђЂУІЦт╣▓сЂ«сѓ»сѓ╗сѓњТёЪсЂўсЂќсѓІсѓњтЙЌсЂЙсЂЏсѓЊРЮЌ сЂЙсЂѓсђЂсЂЮсЂЊсЂ»сЂітЦйсЂ┐сЂД­ЪўЅ

