ТюгТЮЦсЂ»Сй┐ућесЂЎсѓІУеђУфъсѓхсЃ╝сЃљсЃ╝сЂ«setupсЂћсЂесЂФcapabilitiesсѓњсѓфсЃ╝сЃљсЃ╝сЃЕсѓцсЃЅсЂЎсѓІт┐ЁУдЂсЂїсЂѓсѓісЂЙсЂЎсЂїсђЂ сЂЊсЂ«сѓхсѓцсЃѕсЂДсЂ»mason-lspconfigсЂДсЂЙсЂесѓЂсЂдУАїсЂєТќ╣Т│ЋсѓњсЂесЂБсЂдсЂЇсЂЙсЂЌсЂЪРўђ№ИЈ сЂфсЂ«сЂДсђЂсЂЊсѓїсѓѓсЂЙсЂесѓЂсЂду░АтЇўсЂФсѓёсЂБсЂАсѓЃсЂёсЂЙсЂЌсѓЄсЂє­Ъўј mason.luaсѓњжќІсЂёсЂдсЂЊсѓЊсЂфсѓЊсЂЌсЂесЂЉсЂ░OKсЂДсЂЎ­ЪДџРђЇРЎђ№ИЈ­ЪДџ extensions/mason.lua require('mason-lspconfig').setup_handlers { function(server_name)
- require('lspconfig')[server_name].setup {}
+ require('lspconfig')[server_name].setup {
+ capabilities = require('cmp_nvim_lsp').default_capabilities(),
+ } end,
} СИђуХ▓ТЅЊт░йсЂДсЂЎсЂГ­ЪЈЮ№ИЈ СйхсЂЏсЂдpackerсЂФсђїmason-lspconfigсЂ«УеГт«џсЂФcmp-nvim-lspсѓњСй┐ућесЂЎсѓІсѓѕРЮЌсђЇсђЂсЂеТЋЎсЂѕсЂдсЂісЂёсЂдсЂѓсЂњсѓІсЂесЂЋсѓЅсЂФт«Ѕт┐Ѓ­ЪљХ extensions/init.lua use { 'williamboman/mason.nvim', config = function() require 'extensions.mason' end, requires = { 'williamboman/mason-lspconfig.nvim', 'neovim/nvim-lspconfig',
+ 'hrsh7th/cmp-nvim-lsp', } } сЂЊсѓїсЂасЂЉсѓёсЂБсЂдсЂісЂЉсЂ░сђЂсЂѓсЂесЂ»mason-lspconfigсЂїтЁесЂдсЂ«УеђУфъсѓхсЃ╝сЃљсЃ╝сЂФжЂЕућесЂЌсЂдсЂЈсѓїсѓІсЂ»сЂџсЂДсЂЎсђѓ

