356.body:
сЂЙсЂџсђЂсЂёсЂцсѓѓСй┐сЂБсЂдсЂёсѓІluaсЃЄсѓБсЃгсѓ»сЃѕсЃфсЂетљїтѕЌсЂФsnippetsсЂесЂёсЂєсЃЄсѓБсЃгсѓ»сЃѕсЃфсѓњСйюсѓісЂЙсЂЌсѓЄсЂєсђѓ mkdir snippets сЂДсђЂсЂЮсЂ«СИГсЂДС╗ЦСИІ2сЂцсЂ«jsonсЃЋсѓАсѓцсЃФсѓњСйюТѕљсЂЌсЂдсЂЈсЂасЂЋсЂёсђѓ package.json ~/.config/nvim/snippets/package.json { "categories": ["Snippets"], "name": "my-snippets", "contributes": { "snippets": [ { "language": [ "all" ], "path": "all.json" } ] }
} С╗ітЏъсЂ»сѓхсЃ│сЃЌсЃФсЂфсЂ«сЂДlanguageсЂФсЂ»allсѓњТїЄт«џсЂЌсЂдсЂёсЂЙсЂЎсЂїсђЂ СЙІсЂѕсЂ░luaсЃ╗markdownсЂфсЂЕсђЂУеђУфъсЂћсЂесЂФу┤░сЂІсЂЈТїЄт«џсЂЎсѓІсЂЊсЂесѓѓсЂДсЂЇсЂЙсЂЎ­ЪўЅ Snippets Json File уХџсЂёсЂдсђЂУеђУфъсЂФт»ЙсЂЌсЂдСй┐ућесЂЎсѓІсѓ╣сЃІсЃџсЃЃсЃѕсѓњт«џуЙЕсЂЌсЂдсЂёсЂЇсЂЙсЂЎРЮЌ ~/.config/nvim/snippets/all.json { "example": { "prefix": "test", "body": ["hello snippets!!"], "description": "example snippets" }
} Note сЂЊсЂЊсЂЙсЂДсЂДсђЂсЃЋсѓАсѓцсЃФжЁЇуй«сЂ»сЂЊсѓЊсЂфТёЪсЂўсЂФсЂфсѓісЂЙсЂЎсђѓ

37.body:
сЂЋсЂдсђЂт╝ЋсЂЇуХџсЂЇformat.luaсЂФУ┐йУеўсЂЌсЂдсЂёсЂЇсЂЙсЂЌсѓЄсЂєсђѓС╗ітЏъсЂ»сѓ┐сЃќсѓ┐сѓцсЃѕсЃФсЂДсЂЎсђѓ format.lua local HEADER = '№ёа' -- ТќЄтГЌтїќсЂЉсЂЌсЂАсѓЃсЂБсЂдсѓІсЂІсѓѓсЂЌсѓїсЂЙсЂЏсѓЊсЂїсђЂсѓбсѓцсѓ│сЃ│сЃЋсѓЕсЃ│сЃѕтЁЦсЂБсЂдсЂЙсЂЎсђѓ local SYMBOL_COLOR = { '#ffb2cc', '#a4a4a4' }
local FONT_COLOR = { '#dddddd', '#888888' }
local BACK_COLOR = '#2d2d2d'
local HOVER_COLOR = '#434343' wezterm.on('format-tab-title', function(tab, tabs, panes, config, hover, max_width) local index = tab.is_active and 1 or 2 local bg = hover and HOVER_COLOR or BACK_COLOR local zoomed = tab.active_pane.is_zoomed and '­Ъћј ' or ' ' return { { Foreground = { Color = SYMBOL_COLOR[index] } }, { Background = { Color = bg } }, { Text = HEADER .. zoomed }, { Foreground = { Color = FONT_COLOR[index] } }, { Background = { Color = bg } }, { Text = tab.active_pane.title }, }
end) сЂЊсѓїсѓѓсѓдсѓБсЃ│сЃЅсѓдсѓ┐сѓцсЃѕсЃФсЂетљїсЂўсѓѕсЂєсЂФсђЂwezterm.onсѓњСй┐сЂБсЂдformat-tab-titleсѓцсЃЎсЃ│сЃѕсЂ«тЄдуљєсѓњТЏИсЂёсЂдсЂёсЂЙсЂЎсђѓ УЅ▓сЂ»жЂЕт«юУф┐ТЋ┤сЂЌсЂдсЂЈсЂасЂЋсЂёсђѓ format-tab-title The format-tab-title event is emitted when the text for a tab title needs to be recomputed. format-tab-title сѓцсЃЎсЃ│сЃѕсЂ»сђЂсѓ┐сЃќсѓ┐сѓцсЃѕсЃФсЂ«сЃєсѓГсѓ╣сЃѕсѓњтєЇУеѕу«ЌсЂЎсѓІт┐ЁУдЂсЂїсЂѓсѓІсЂесЂЇсЂФуЎ║УАїсЂЋсѓїсЂЙсЂЎсђѓ сЂЊсѓїсѓѓсѓдсѓБсЃ│сЃЅсѓдсѓ┐сѓцсЃѕсЃФсЂесЂ╗сЂ╝тљїсЂўсЂДсЂЎсЂГсђѓ ТЅђсђЁсЂДуіХТЁІсЂФсѓѕсЂБсЂдУАеуц║сЂЎсѓІсѓѓсЂ«сѓњтцЅсЂѕсЂдсЂёсЂЙсЂЎсЂїсђЂсѓёсЂБсЂдсЂёсѓІсЂЊсЂесЂ»zoomedсЂеhoverсЂ«тЈ»УдќтїќсЂДсЂЎсЂГ­ЪцЕ

370.body:
сѓѓсЂєСИђтђІсЂасЂЉсђЂтцДС║ІсЂфсѓѓсЂ«сѓњсѓёсЂБсЂАсѓЃсЂёсЂЙсЂЌсѓЄсЂєРЮЌ Info Use this field to provide the path to a specific node version such as one installed by nvm. Node.js version must be 16.x or newer. сЂЊсЂ«сЃЋсѓБсЃ╝сЃФсЃЅсЂ»сђЂnvm сЂФсѓѕсЂБсЂдсѓцсЃ│сѓ╣сЃѕсЃ╝сЃФсЂЋсѓїсЂЪсѓѓсЂ«сЂфсЂЕсђЂуЅ╣т«џсЂ« node сЃљсЃ╝сѓИсЃДсЃ│сЂИсЂ«сЃЉсѓ╣сѓњТЈљСЙЏсЂЎсѓІсЂЪсѓЂсЂФСй┐ућесЂЌсЂЙсЂЎсђѓ Node.js сЂ«сЃљсЃ╝сѓИсЃДсЃ│сЂ» 16.x С╗ЦжЎЇсЂДсЂѓсѓІт┐ЁУдЂсЂїсЂѓсѓісЂЙсЂЎсђѓ copilot_node_command = vim.fn.expand("$HOME") .. "/.config/nvm/versions/node/v16.14.2/bin/node", сЂАсѓЄсЂБсЂеуњ░тбЃсЂФсѓѕсЂБсЂдсЂ»тцДтцЅсЂІсѓѓсЂЌсѓїсЂфсЂёсѓЊсЂДсЂЎсЂї...сђѓ extensions.copilot.lua - require('copilot').setup {}
+ require('copilot').setup {
+ copilot_node_command = 'node', -- node сЂ«сЃЉсѓ╣сѓњТїЄт«џсЂЎсѓІ
+ } Node.js УЕдсЂЌсЂФwhich nodeсЂБсЂдсѓёсЂБсЂдсЂ┐сЂдсђЂсЂфсѓЊсЂІсЂЮсѓїсЂБсЂйсЂёсЃЉсѓ╣сЂїтЄ║сЂдсЂЈсѓІсѓѕсЂєсЂфсѓЅтцДСИѕтцФсЂДсЂЌсѓЄсЂєсђѓ сѓѓсЂЌСйЋсѓѓтЄ║сЂдсЂЊсЂфсЂёсѓѕсЂєсЂфсѓЅnode.jsсѓњсѓцсЃ│сѓ╣сЃѕсЃ╝сЃФсЂЌсЂЙсЂЌсѓЄсЂєРЮЌ node.jsсЂ»сѓѓсЂ»сѓёУХЁсЃАсѓИсЃБсЃ╝жЂИТЅІсЂфсЂ«сЂДсђЂТќ╣Т│ЋсЂ»сЂфсѓЊсЂ╝сЂДсѓѓсЂѓсѓісЂЙсЂЎсЂІсѓЅсЂГ­Ъўє Note Т»јт║дсЂіжд┤ТЪЊсЂ┐сђЂbrewсђЂaptсђЂdnf сЂфсЂЕсѓњСй┐ућесЂЌсЂдсѓѓсѓцсЃ│сѓ╣сЃѕсЃ╝сЃФсЂДсЂЇсЂЙсЂЎсђѓ СИђт┐юnode -vсѓѓсѓёсЂБсЂдсЂ┐сЂдсђЂ16.x С╗ЦжЎЇсЂасЂфсђюсЂБсЂдсЂфсЂБсЂдсѓїсЂ░OKсЂДсЂЎРЮЌ...сЂ«сђЂсЂ»сЂџсЂДсЂЎсђѓ Tip сЃљсЃ╝сѓИсЃДсЃ│16.xС╗ЦжЎЇсЂесЂ»УеђсЂєсѓѓсЂ«сЂ«сђЂ2023-09-11 сЂДсѓѓсЂєEnd-of-lifeсЂфсЂ«сЂДсђЂ18.xсЂ«Тќ╣сЂїУЅ»сЂёсЂ»сЂџсЂДсЂЎсђѓ (СИісЂ«СЙІсЂДсЂ»ТђЮсЂёсЂБсЂЇсѓі16.xсЂфсѓЊсЂДсЂЎсЂЉсЂЕсЂГ­ЪўЁ) сЂфсѓЊсЂфсѓЅ 2023-10-24 сЂІсѓЅсЂ»Long-Term Support сЂї 20.xсЂФуД╗сѓІсЂ«сЂДсђЂ(Тћ»жџюсЂфсЂЉсѓїсЂ░) сѓѓсЂєсЂЊсѓїСй┐сЂєТќ╣сЂїсЂёсЂёсѓЊсЂўсѓЃсЂфсЂёсЂІсЂљсѓЅсЂёТђЮсЂБсЂдсЂЙсЂЎ­Ъљ┐№ИЈ Release schedule Release Status Codename Initial Release Active LTS Start Maintenance Start End-of-life 16.x Maintenance Gallium 2021-04-20 2021-10-26 2022-10-18 2023-09-11 18.x LTS Hydrogen 2022-04-19 2022-10-25 2023-10-18 2025-04-30 20.x Current 2023-04-18 2023-10-24 2024-10-22 2026-04-30 (Рђ╗ 2023-06-12 уЈЙтюе) Question сЂЊсѓїсѓѓсЂфсЂюсЂІсЂЊсЂ«сѓхсѓцсЃѕсЂДСй┐сЂБсЂдсЂёсѓІFedoraу│╗сЂ«уњ░тбЃсЂДсЂ»dnfсЂІсѓЅсѓцсЃ│сѓ╣сЃѕсЃ╝сЃФсЂЌсЂЪсЂасЂЉсЂДсЂ»СИіТЅІсЂЈсЂёсЂЇсЂЙсЂЏсѓЊсЂДсЂЌсЂЪ­ЪўГ СИђт┐юсђЂ16.x сЂфсѓЊсЂДсЂЎсЂЉсЂЕсЂГ­ЪЦ╣ сЂфсЂ«сЂДтЏ░сЂБсЂдсЂЪсѓЊсЂДсЂЎсЂЉсЂЕ...сђѓ УЕдсЂЌсЂФnvmсѓњСй┐сЂБсЂдv20.3.0сѓњтЁЦсѓїсЂдсђЂсЂЮсѓЊсЂДcopilot_node_commandсЂДТїЄт«џсЂЌсЂдсЂ┐сЂЪсѓЅСИіТЅІсЂЈжБЏсѓЊсЂасѓЊсЂДсЂЎ­Ъў« сЂфсѓЊсЂДсЂДсЂЌсѓЄ­ЪўЁ

385.body:
Setup It is recommended to disable copilot.lua's suggestion and panel modules, as they can interfere with completions properly appearing in copilot-cmp. copilot.luaсЂ«suggestionсЃбсѓИсЃЦсЃ╝сЃФсЂеpanelсЃбсѓИсЃЦсЃ╝сЃФсЂ»сђЂ copilot-cmpсЂДжЂЕтѕЄсЂФУАеуц║сЂЋсѓїсѓІУБют«їсѓњтдет«│сЂЎсѓІсЂЊсЂесЂїсЂѓсѓІсЂ«сЂДсђЂуёАті╣сЂФсЂЎсѓІсЂЊсЂесѓњсЂітІДсѓЂсЂЌсЂЙсЂЎсђѓ To do so, simply place the following in your copilot.lua config: сЂЮсЂ«сЂЪсѓЂсЂФсЂ»сђЂcopilot.luaсЂ«УеГт«џсЂФС╗ЦСИІсѓњУеўУ┐░сЂЌсЂдсЂЈсЂасЂЋсЂё№╝џ сЂ»сЂёсђЂтЁЦсѓїсЂЙсЂЌсѓЄсЂє­ЪўЅ extensions/copilot.lua require('copilot').setup {
+ suggestion = { enabled = false },
+ panel = { enabled = false }, copilot_node_command = 'node', }

392.body:
cmp-buffer nvim-cmp source for buffer words. сЃљсЃЃсЃЋсѓАтєЁтЇўУфъсЂ« nvim-cmp сѓйсЃ╝сѓ╣сђѓ extensions/init.lua use { 'hrsh7th/nvim-cmp', config = function() require 'extensions.nvim-cmp' end, requires = { 'hrsh7th/cmp-nvim-lsp',
+ 'hrsh7th/cmp-buffer', (СИГуЋЦ) }
} extensions/nvim-cmp.lua sources = cmp.config.sources { { name = 'nvim_lsp' }, { name = 'luasnip' }, { name = 'copilot' },
+ { name = 'buffer' }, }, before after extensions/nvim-cmp.lua cmp.setup { (СИГуЋЦ) } +cmp.setup.cmdline({ '/', '?' }, {
+ sources = cmp.config.sources {
+ {
+ name = 'buffer',
+ option = {
+ keyword_pattern = [[\k\+]],
+ },
+ },
+ },
+}) keyword_pattern (type: string) Default: [[\%(-\?\d\+\%(\.\d\+\)\?\|\h\w*\%([\-.]\w*\)*\)]] A vim's regular expression for creating a word list from buffer content. сЃљсЃЃсЃЋсѓАсЂ«тєЁт«╣сЂІсѓЅтЇўУфъсЃфсѓ╣сЃѕсѓњСйюТѕљсЂЎсѓІсЂЪсѓЂсЂ«vimсЂ«ТГБУдЈУАеуЈЙсђѓ You can set this to [[\k\+]] if you want to use the iskeyword option for recognizing words. Lua's [[ ]] string literals are particularly useful here to avoid escaping all of the backslash (\) characters used for writing regular expressions. iskeywordсѓфсЃЌсѓисЃДсЃ│сѓњСй┐сЂБсЂдтЇўУфъсѓњУфЇУГўсЂЌсЂЪсЂёта┤тљѕсЂ»сђЂсЂЊсѓїсѓњ[[\k\+]]сЂФУеГт«џсЂЌсЂЙсЂЎсђѓ LuaсЂ«[[ ]]ТќЄтГЌтѕЌсЃфсЃєсЃЕсЃФсЂ»сђЂТГБУдЈУАеуЈЙсЂ«УеўУ┐░сЂФСй┐ућесЂЋсѓїсѓІсЃљсЃЃсѓ»сѓ╣сЃЕсЃЃсѓисЃЦ(\) сЂ«сѓесѓ╣сѓ▒сЃ╝сЃЌсѓњтЏъжЂ┐сЂЎсѓІсЂЪсѓЂсЂФуЅ╣сЂФТюЅућесЂДсЂЎсђѓ before after

393.body:
cmp-cmdline nvim-cmp source for vim's cmdline. vim сЂ« cmdline уће nvim-cmp сѓйсЃ╝сѓ╣сђѓ extensions/init.lua use { 'hrsh7th/nvim-cmp', config = function() require 'extensions.nvim-cmp' end, requires = { 'hrsh7th/cmp-nvim-lsp', 'hrsh7th/cmp-buffer',
+ 'hrsh7th/cmp-cmdline', (СИГуЋЦ) }
} extensions/nvim-cmp.lua +cmp.setup.cmdline(':', {
+ mapping = cmp.mapping.preset.cmdline(),
+ sources = cmp.config.sources {
+ { name = 'cmdline' },
+ },
+}) cmp.setup.cmdline({ '/', '?' }, {
+ mapping = cmp.mapping.preset.cmdline(), sources = cmp.config.sources { { name = 'buffer', option = { keyword_pattern = [[\k\+]], }, }, },
}) before after

394.body:
cmp-path nvim-cmp source for filesystem paths. сЃЋсѓАсѓцсЃФсѓисѓ╣сЃєсЃасЃЉсѓ╣ућесЂ« nvim-cmp сѓйсЃ╝сѓ╣сђѓ extensions/init.lua use { 'hrsh7th/nvim-cmp', config = function() require 'extensions.nvim-cmp' end, requires = { 'hrsh7th/cmp-nvim-lsp', 'hrsh7th/cmp-buffer', 'hrsh7th/cmp-cmdline',
+ 'hrsh7th/cmp-path', (СИГуЋЦ) }
} extensions/nvim-cmp.lua cmp.setup { (СИГуЋЦ) sources = cmp.config.sources { { name = 'nvim_lsp' }, { name = 'luasnip' }, { name = 'copilot' }, { name = 'buffer' },
+ { name = 'path' }, }, (СИГуЋЦ)
} cmp.setup.cmdline(':', { sources = cmp.config.sources { { name = 'cmdline' },
+ { name = 'path' }, },
})

395.body:
lspkind-nvim This tiny plugin adds vscode-like pictograms to neovim built-in lsp: сЂЊсЂ«т░ЈсЂЋсЂфсЃЌсЃЕсѓ░сѓцсЃ│сЂ»сђЂneovim сЂ«тєЁУћх lsp сЂФ vscode сЂ«сѓѕсЂєсЂфуххТќЄтГЌсѓњУ┐йтіасЂЌсЂЙсЂЎ№╝џ extensions/init.lua use { 'hrsh7th/nvim-cmp', config = function() require 'extensions.nvim-cmp' end, requires = { 'hrsh7th/cmp-nvim-lsp', 'hrsh7th/cmp-buffer', 'hrsh7th/cmp-path', 'hrsh7th/cmp-cmdline',
+ 'onsails/lspkind-nvim', (СИГуЋЦ) }
} extensions/nvim-cmp.lua cmp.setup { -- (СИГуЋЦ) formatting = { format = require('lspkind').cmp_format { mode = 'symbol', preset = 'codicons', }, },
} Highlighting & icon (copilot-cmp) Copilot's cmp source now has a builtin highlight group CmpItemKindCopilot. To add an icon to copilot for lspkind, simply add copilot to your lspkind symbol map. Copilot сЂ« cmp сѓйсЃ╝сѓ╣сЂФсђЂухёсЂ┐УЙ╝сЂ┐сЂ«сЃЈсѓцсЃЕсѓцсЃѕсѓ░сЃФсЃ╝сЃЌCmpItemKindCopilotсЂїУ┐йтіасЂЋсѓїсЂЙсЂЌсЂЪсђѓ lspkind сЂ« copilot сЂФсѓбсѓцсѓ│сЃ│сѓњУ┐йтіасЂЎсѓІсЂФсЂ»сђЂlspkind сЂ«сѓисЃ│сЃюсЃФсЃъсЃЃсЃЌсЂФ copilot сѓњУ┐йтіасЂЎсѓІсЂасЂЉсЂДсЂЎсђѓ Alternatively, you can add Copilot to the lspkind symbol_map within the cmp format function. сЂЙсЂЪсЂ»сђЂcmp сЃЋсѓЕсЃ╝сЃъсЃЃсЃѕжќбТЋ░тєЁсЂД lspkind symbol_mapсЂФ Copilot сѓњУ┐йтіасЂЎсѓІсЂЊсЂесѓѓсЂДсЂЇсЂЙсЂЎсђѓ extensions/nvim-cmp.lua cmp.setup { -- (СИГуЋЦ) formatting = { format = require('lspkind').cmp_format { mode = 'symbol', preset = 'codicons',
+ symbol_map = { Copilot = '№ёЊ' }, }, },
} before after (Plus: cmp-path) (Plus: cmp-cmdline)

