} extensions/init.lua use { 'folke/trouble.nvim',
+ config = function() require 'extensions.trouble' end, requires = 'nvim-tree/nvim-web-devicons',
} There will be an answer Let it be уГћсЂѕсЂ»т┐ЁсЂџсЂѓсѓІсѓЊсЂасЂІсѓЅ сЂфсѓІсѓѕсЂєсЂФсЂфсѓІсѓѕ

42.body:
С╗іт║дсЂ»сѓ╣сЃєсЃ╝сѓ┐сѓ╣сЃљсЃ╝сѓњжБЙсѓіС╗ўсЂЉсЂАсѓЃсЂісЂБсЂІсЂфсЃ╝сЂеТђЮсЂёсЂЙсЂЎ­Ъўє status.luaсЂесЂёсЂєсЃЋсѓАсѓцсЃФсѓњУ┐йтіасЂЌсЂЙсЂЌсѓЄсЂєсђѓ status.lua local wezterm = require 'wezterm' wezterm.on('update-status', function(window, pane)
end) сѓѓсЂєсЂіжд┤ТЪЊсЂ┐сЂДсЂЎсЂГ­ЪўЅ wezterm.luaсЂІсѓЅУфГсЂ┐УЙ╝сЂ┐сЂЙсЂЌсѓЄсЂєсђѓ wezterm.lua require 'status' -- РєЊ сЂЊсЂЊсЂЙсЂДсЂДУЅ▓сђЁсЂеУеўУ┐░сЂЌсЂдсЂЇсЂЪсЂесЂЊсѓЇ
return { -- сђю
} сЂЋсЂдсђЂwezterm.onсѓњтѕЕућесЂЌсЂдupdate-statusсѓцсЃЎсЃ│сЃѕсѓњсЃЋсЃЃсѓ»сЂЌсЂЙсЂЎсђѓ update-status The update-status event is emitted periodically (based on the interval specified by the status_update_interval configuration value). There is no defined return value for the event, but its purpose is to allow you the chance to carry out some activity and then ultimately call window:set_right_status or window:set_left_status. update-status сѓцсЃЎсЃ│сЃѕсЂ»т«џТюЪуџёсЂФуЎ║УАїсЂЋсѓїсЂЙсЂЎ (status_update_interval УеГт«џтђцсЂДТїЄт«џсЂЋсѓїсЂЪжќЊжџћсЂФтЪ║сЂЦсЂЈ)сђѓ сЂЊсЂ«сѓцсЃЎсЃ│сЃѕсЂ«Тѕ╗сѓітђцсЂ»т«џуЙЕсЂЋсѓїсЂдсЂёсЂЙсЂЏсѓЊсЂїсђЂсЂЮсЂ«уЏ«уџёсЂ»сђЂСйЋсѓЅсЂІсЂ«Т┤╗тІЋсѓњУАїсЂёсђЂТюђухѓуџёсЂФ window:set_right_status сЂЙсЂЪсЂ» window:set_left_status сѓњтЉ╝сЂ│тЄ║сЂЎТЕЪС╝џсѓњТЈљСЙЏсЂЎсѓІсЂЊсЂесЂДсЂЎсђѓ сЂесЂ«сЂЊсЂесЂфсЂ«сЂДсђЂwezterm.luaсЂ«СИГсЂДсѓ╣сЃєсЃ╝сѓ┐сѓ╣ТЏ┤Тќ░жќЊжџћсѓњТїЄт«џсЂЌсЂдсЂісЂЇсЂЙсЂЌсѓЄсЂєсђѓ wezterm.lua return { status_update_interval = 1000,
} status_update_interval Specifies the number of milliseconds that need to elapse between triggering the update-right-status hook. update-right-status сЃЋсЃЃсѓ»сЂ«сЃѕсЃфсѓгсЃ╝сЂесЂфсѓІсЂЙсЂДсЂФт┐ЁУдЂсЂфсЃЪсЃфуДњсѓњТїЄт«џсЂЌсЂЙсЂЎсђѓ сЃЄсЃЋсѓЕсЃФсЃѕсЂ»1000сЃЪсЃфуДњ(=1уДњ)сЂДсЂЎсђѓсЂЮсЂ«сЂЙсЂЙсЂДУЅ»сЂЉсѓїсЂ░т┐ЁУдЂсЂѓсѓісЂЙсЂЏсѓЊсђѓ Warning сЃЅсѓГсЃЦсЃАсЃ│сЃѕсЂДсЂ»update-right-statusсЂесЂфсЂБсЂдсЂёсЂЙсЂЎсЂїсђЂтЅЇтЄ║сЂ«update-statusсЂїтЙїуХЎС╗ЋТДўсЂесЂфсЂБсЂдсЂёсѓІсЂ«сЂДсђЂсЂЊсЂАсѓЅсѓњСй┐сЂБсЂдсЂёсЂЇсЂЙсЂЎсђѓ Success сЂЮсѓїсЂДсЂ»ТгАсЂФжђ▓сЂ┐сЂЙсЂЌсѓЄсЂєРЮЌ

428.body:
сЂЊсЂєсЂёсЂєсЂ«тцДтЦйсЂЇРЮЌ defaults { performance = { cache = { enabled = true, }, reset_packpath = true, -- reset the package path to improve startup time rtp = { reset = true, -- reset the runtime path to $VIMRUNTIME and your config directory ---@type string[] paths = {}, -- add any custom paths here that you want to includes in the rtp ---@type string[] list any plugins you want to disable here disabled_plugins = { -- "gzip", -- "matchit", -- "matchparen", -- "netrwPlugin", -- "tarPlugin", -- "tohtml", -- "tutor", -- "zipPlugin", }, }, },
} ­ЪћИ rtp сѓёсЂѓсѓЊ­ЪЦ▒ Keeping an eye on the world going by my window 2 Taking my time уфЊсЂ«тцќсѓњУАїсЂЇС║цсЂєСИќуЋїсѓњУдІуХџсЂЉсѓІ ТЎѓжќЊсѓњсЂІсЂЉсЂд ­Ъћ╣disabled_plugins Info list any plugins you want to disable here уёАті╣сЂФсЂЌсЂЪсЂёсЃЌсЃЕсѓ░сѓцсЃ│сѓњсЂЊсЂЊсЂФтѕЌТїЎсЂЎсѓІ сѓ│сЃАсЃ│сЃѕсѓбсѓдсЃѕсЂЋсѓїсЂдсЂёсѓІсѓѓсЂ«сѓњсЂёсЂЈсЂцсЂІтцќсЂЌсЂдсЂ┐сЂЙсЂЌсѓЄсЂєРЮЌ extensions/init.lua local opts = { performance = { rtp = { disabled_plugins = { 'gzip', 'matchit', --'matchparen', --'netrwPlugin', 'tarPlugin', 'tohtml', 'tutor', 'zipPlugin', }, }, },
} сѓЈсЂЪсЂЌсЂ»С╗ЦСИІсЂ«2сЂцсѓњсѓ│сЃАсЃ│сЃѕсѓбсѓдсЃѕсЂ«сЂЙсЂЙсЂФсЂЌсЂдсЂёсЂЙсЂЎсђѓ Note disabledсѓњсѓ│сЃАсЃ│сЃѕсѓбсѓдсЃѕсЂЌсЂЪсЂЙсЂЙсЂФсЂЎсѓІсЂ«сЂДсђЂenabledсЂ«сЂЙсЂЙсЂФсЂЎсѓІсЂБсЂдсЂЊсЂесЂДсЂЎсЂГсђѓ ...УфгТўјсЂїсѓёсѓёсЂЊсЂЌсЂёсЂДсЂЎсЂГ­Ъў« РЌйmatchparen С║║сЂФсѓѕсЂБсЂдсЂ»СИЇУдЂсЂасЂеТђЮсЂєсЂІсѓѓсЂЌсѓїсЂЙсЂЏсѓЊсЂїсђЂсѓЈсЂЪсЂЌсЂ»сЂЊсѓїтЦйсЂЇсЂфсѓЊсЂДсЂЎсѓѕсЂГсђю­Ъўє custom_highlights сЂДсѓФсѓ╣сѓ┐сЃъсѓцсѓ║сЂЌсЂдсЂёсѓІсЂљсѓЅсЂёсЂфсЂ«сЂДРЮЌ РЌйnetrwPlugin сЂЊсѓїсЂ»сђїnvim-treeсѓњСй┐сЂєта┤тљѕсЂ»уёАті╣тїќсЂЌсЂесЂёсЂдсЂГсђЇсЂДсЂіжд┤ТЪЊсЂ┐сЂ« netrw сЂДсЂЎ­ЪўЅ сѓѓсЂєсЂЎсЂДсЂФуёАті╣тїќсЂЎсѓІсѓ│сЃ╝сЃЅсЂїтЁЦсЂБсЂдсЂёсѓІсЂ«сЂДсђЂсЂЊсЂЊсЂДсЂ»т┐ЁУдЂсЂ»сЂфсЂёсЂІсЂфсђюсЂБсЂдсЂёсЂєУђЃсЂѕТќ╣сЂДсЂЎсђѓ сЂЙсЂѓсђЂсЂЕсЂБсЂАсЂДуёАті╣тїќсЂЌсЂдсѓѓсЂИсЃ╝сЂЇсЂфсѓЊсЂўсѓЃсЂфсЂёсЂІсЂфРЂЅ№ИЈ

433.body:
сЂЊсѓїсЂЙсЂДсЂ«packerсЂ«УеГт«џсЂФУдІТЁБсѓїсЂдсЂёсѓІсЂесђЂ сЂёсЂЇсЂфсѓісЂАсѓЄсЂБсЂеТЇ╗сЂЈсѓїсЂЪсЂЊсЂесЂЌсЂдсѓІсѓѕсЂєсЂФУдІсЂѕсѓІсЂІсѓѓсЂЌсѓїсЂфсЂёсѓЊсЂДсЂЎсЂїсђЂсѓЈсЂЪсЂЌсЂ»сЂЊсѓЊсЂфТЏИсЂЇТќ╣сЂФсЂЌсЂдсЂЙсЂЎсђѓ extensions/init.lua Тќ░сЂЌсЂЈpluginsсЂесЂёсЂє localтцЅТЋ░ сѓњуй«сЂЇсЂЙсЂЎсђѓСИГУ║ФсЂ»сЂЙсЂасђЂсЂІсѓЅсЂБсЂйсЂДсЂИсЃ╝сЂЇсЂДсЂЎ­ЪўЅ тЅЇу»ђсЂДжђђжЂ┐сЂЋсЂЏсЂЪсЃЌсЃЕсѓ░сѓцсЃ│сЂ«сЃфсѓ╣сЃѕсЂ»сђЂтЁежЃесЂЊсЂЊсЂФтЁЦсѓїсЂдсЂёсЂЇсЂЙсЂЎ­Ъўї local plugins = { } сѓЊсЂДсђЂсЂЊсЂЊсЂ»тЅЇтЏъсЂ« 17.1 lazy.nvim - Configuration сЂДТЏИсЂёсЂЪсѓ│сЃ╝сЃЅсЂїсЂѓсЂБсЂд...сђЂ local opts = { -- ...
} сЂѓсЂесЂ»сђЂ 17.1 lazy.nvim - Installation сЂ«сѓ│сЃ╝сЃЅсЂДсЂЎсђѓ local lazypath = vim.fn.stdpath('data') .. '/lazy/lazy.nvim'
if not vim.loop.fs_stat(lazypath) then vim.fn.system({ 'git', 'clone', '--filter=blob:none', 'https://github.com/folke/lazy.nvim.git', '--branch=stable', lazypath, })
end
vim.opt.rtp:prepend(lazypath) require("lazy").setup() Note сЂЊсЂ«УеўУ┐░сЂДУеђсЂѕсЂ░сђЂsetup()сЂЋсЂѕСИђуЋфСИІсЂФсЂёсѓїсЂ░С╗ќсЂ«сѓ│сЃ╝сЃЅсЂ«жаєуЋфсЂ»уЅ╣сЂФтЋЈжАїсЂФсЂфсѓЅсЂфсЂёсЂ»сЂџсЂДсЂЎсђѓ extensions/init.lua сЂЮсЂЌсЂЪсѓЅсђЂСИђуЋфСИІсЂФсЂѓсѓІsetupсѓњТЏИсЂЇТЈЏсЂѕсЂЙсЂЎсђѓ - require("lazy").setup()
+ require('lazy').setup(plugins, opts)

