} сЂДсђЂlualine.luaсЂФухёсЂ┐УЙ╝сЂ┐сЂЙсЂЌсѓЄсЂєсђѓ сѓѓсЂАсѓЇсѓЊсђЂstatuslineсЂДсѓѓtablineсЂДсѓѓсђЂaсЂасѓЇсЂєсЂеxсЂасѓЇсЂєсЂетЦйсЂЇсЂфта┤ТЅђсЂФтЁЦсѓїсЂАсѓЃсЂёсЂЙсЂЌсѓЄсЂєРЮЌ extensions/lualine.lua require("lualine").setup { sections = { lualine_x = { { require("lazy.status").updates, cond = require("lazy.status").has_updates, color = { fg = "#ff9e64" }, }, }, },
} Note сѓЈсЂЪсЂЌсЂ»tablineсЂФтЁЦсѓїсЂдсЂЙсЂЎсЂїсђЂсЂЮсЂ«та┤тљѕсЂ»сЂЊсѓЊсЂфТёЪсЂўсЂДтЄ║сЂдсЂЇсЂЙсЂЎ­Ъўё сЂЊсЂ«сѓ╣сѓ»сЃфсЃ╝сЃ│сѓисЃДсЃЃсЃѕсЂДсЂ»сЂєсЂБсЂІсѓі nvim-notify сѓњСй┐сЂБсЂдсѓІсѓЊсЂДсЂЎсЂїсђЂ Тћ╣сѓЂсЂдУдІсЂЪсѓЅсЂЊсѓїсђЂсЂфсѓЊсЂІсЂЎсЂБсЂћсЂёуХ║ж║ЌсЂўсѓЃсЂфсЂё...РЮЊ сЂєсЂБсЂесѓісЂЌсЂАсѓЃсЂБсЂЪ­Ъўі ТгАтЏъсЂ»сЂЊсѓїсѓёсѓЇсЂєсЂІсЂф...сђѓ ...сЂѓсѓїРЮЊсЂфсѓЊсЂІтЁеуёХсЂісѓЈсѓЊсЂГсЂЄсЂф­ЪЎё Don't you know that inside There's a love you can't hide тљЏсЂ»уЪЦсѓЅсЂфсЂёсЂ«№╝Ъ жџасЂЌсЂЇсѓїсЂфсЂёТёЏсЂїсЂѓсѓІсЂЊсЂе

