} configсЂ»ТгАсЂ«жаЁсЂДУАїсЂєсЂесЂЌсЂдсђЂсѓцсЃ│сѓ╣сЃѕсЃ╝сЃФжЃетѕєсѓњтЁѕсЂФТИѕсЂЙсЂЏсЂдсЂЌсЂЙсЂёсЂЙсЂЌсѓЄсЂєРЮЌ extensions/init.lua { 'jay-babu/mason-null-ls.nvim', event = { 'BufReadPre', 'BufNewFile' }, dependencies = { 'williamboman/mason.nvim', 'nvimtools/none-ls.nvim', },
