Automatic Setup Usage Automatic Setup is a need feature that removes the need to configure null-ls for supported sources. Sources found installed in mason will automatically be setup for null-ls. УЄфтІЋсѓ╗сЃЃсЃѕсѓбсЃЃсЃЌсЂ»сђЂсѓхсЃЮсЃ╝сЃѕсЂЋсѓїсЂдсЂёсѓІсѓйсЃ╝сѓ╣сЂФт»ЙсЂЌсЂд null-ls сѓњУеГт«џсЂЎсѓІт┐ЁУдЂТђДсѓњтЈќсѓіжЎцсЂЈТЕЪУЃйсЂДсЂЎсђѓ mason сЂФсѓцсЃ│сѓ╣сЃѕсЃ╝сЃФсЂЋсѓїсЂЪсѓйсЃ╝сѓ╣сЂ»УЄфтІЋуџёсЂФ null-ls ућесЂФсѓ╗сЃЃсЃѕсѓбсЃЃсЃЌсЂЋсѓїсЂЙсЂЎсђѓ СЙІсЂѕсЂ░сђЂсЂЮсѓїсЂ»сѓѓсЂєсѓЂсЂАсѓЃсЂЈсЂАсѓЃУеђУфъсЃЌсЃГсЃЋсѓДсЃЃсѓисЃДсЃісЃФсЂїТЅ▒сЂєта┤тљѕсЂ»сђЂ handlersсЂФтђІтѕЦсЂФТЏИсЂёсЂЪТќ╣сЂїсЂЇсЂБсЂАсѓісЂДсЂЇсѓІсЂ»сЂџсЂДсЂЎсђѓ ...сЂЪсЂасђЂсЂЮсЂєсЂДсѓѓсЂфсЂёта┤тљѕсђЂУеђУфъсЂћсЂесЂФСИђтђІСИђтђІсЂ«УеГт«џсѓњсЂЌсЂдсЂёсЂІсЂфсЂЇсѓЃсЂфсѓЅсЂфсЂёсЂБсЂдсЂфсѓІсЂесђЂ mason.nvimсЂїТЈљСЙЏсЂЌсЂдсЂЈсѓїсѓІсЂіТЅІУ╗йсЂЋсЂїсђЂсЂІсЂфсѓіТљЇсЂфсѓЈсѓїсЂдсЂЌсЂЙсЂёсЂЙсЂЎсђѓ сЂДсѓѓсђЂсЂЮсѓїсЂДсЂ»сЂѓсЂЙсѓісЂФсѓѓтІ┐СйЊсЂфсЂёсЂ«сЂДсђЂ сЂЊсѓїсѓњуљєУДБсЂЌсЂЪСИісЂДСй┐ућесЂЎсѓІтѕєсЂФсЂ»сЂёсЂёсѓЊсЂўсѓЃсЂфсЂёсЂІсЂфсђюсЂБсЂдТђЮсЂєсЂЊсЂесЂФсЂЌсЂЙсЂЎРЮЌсЂЮсЂєсЂЌсЂЙсЂЎ­Ъўє And so happy Christmas (War is over) 1 For black and for white For yellow and red ones ж╗њсЂеуЎйсЂ«сЂЪсѓЂсЂФ ж╗ёУЅ▓сЂеУхцсЂасЂБсЂд Let's stop all the fight сЂЎсЂ╣сЂдсЂ«С║ЅсЂёсѓњсѓёсѓЂсѓѕсЂє Example Config Example Config require("mason").setup()
require("mason-null-ls").setup({ handlers = {},
}) See the Default Configuration section to understand how the default configs can be overridden. сЃЄсЃЋсѓЕсЃФсЃѕУеГт«џсѓњСИіТЏИсЂЇсЂЎсѓІТќ╣Т│ЋсЂФсЂцсЂёсЂдсЂ»сђЂ Default Configuration сѓ╗сѓ»сѓисЃДсЃ│сѓњтЈѓуЁДсЂЌсЂдсЂЈсЂасЂЋсЂёсђѓ сЂЊсЂ«сЃџсЃ╝сѓИсЂДсЂ»masonсЂ«setup()сЂ»сѓѓсЂєТИѕсѓЊсЂДсЂёсѓІсѓѓсЂ«сЂесЂЌсЂдуЅ╣сЂФУДдсѓїсЂЙсЂЏсѓЊсђѓ сЂЮсЂ«СИісЂДсђЂсЂЊсЂЊсѓѓlazy.nvimсѓњсѓѓсЂБсЂежа╝сЂБсЂд (ТђасЂЉсЂАсѓЃсЂБсЂд) сЂёсЂёсЂеТђЮсЂёсЂЙсЂЎ­Ъўф lazy.nvimсЂ«ТЈљСЙЏсЂЎсѓІoptsсѓфсЃЌсѓисЃДсЃ│сЂФсЃЉсЃЕсЃАсЃ╝сѓ┐сѓњТїЄт«џсЂЎсѓІсЂесђЂсЂЮсЂ«сЂЙсЂЙсЃЌсЃЕсѓ░сѓцсЃ│сЂ«config()сЂФТИАсЂЌсЂдсЂЈсѓїсЂЙсЂЎсђѓ ­Ъћї Plugin Spec Property Type Description opts table or fun(LazyPlugin, opts:table) opts should be a table (will be merged with parent specs), return a table (replaces parent specs) or should change a table. The table will be passed to the Plugin.config() function. Setting this value will imply Plugin.config() сЂфсЂ«сЂДсђЂсѓисЃ│сЃЌсЃФсЂФсЂЊсѓїсЂасЂЉсЂДТИѕсЂЙсЂЏсЂдсЂЌсЂЙсЂБсЂдсѓѓсЂёсЂёсѓЊсЂўсѓЃсЂфсЂёсЂІсЂф­Ъўї extensions/init.lua { 'jay-babu/mason-null-ls.nvim', event = { 'BufReadPre', 'BufNewFile' }, dependencies = { 'williamboman/mason.nvim', 'nvimtools/none-ls.nvim', },
+ opts = {
+ handlers = {}
+ },
}, Default Configuration сѓњУдІсЂдсЂ«жђџсѓісђЂ сЃЄсЃЋсѓЕсЃФсЃѕсЂДсЂ»nilсЂФсЂфсЂБсЂдсЂёсѓІсЂ«сЂДсђЂсЂЊсѓїсѓњArrayсЂДсѓфсЃ╝сЃљсЃ╝сЃЕсѓцсЃЅсЂЌсЂдсЂёсЂЙсЂЎсђѓ Note сЂ▒сЂБсЂеУдІсЂЪТёЪсЂўсђЂhandlersсЂФт»ЙсЂЌсЂдсђїсЂфсѓЊсѓёсЂЊсЂёсЂц­Ъў«сђЇсЂеТђЮсѓЈсЂфсЂЈсѓѓсЂфсЂёсѓЊсЂДсЂЎсЂїсђЂсЂЊсѓїсЂфсЂёсЂетІЋсЂІсЂфсЂёсЂДсЂЌсѓЄРЮЊ

48.body:
сЂЙсЂџсЂ» wez сЂЋсѓЊсЂ«сѓхсЃ│сЃЌсЃФсѓ│сЃ╝сЃЅсѓњсЂ╗сЂ╝СИИтєЎсЂЌсЂДсЂЎсЂїсђЂСИђсЂцсЂџсЂцТЕЪУЃйсѓњтѕєсЂЉсЂЙсЂЎсђѓ Warning тЁѕсЂФСИІУеўсЂ«сѓ│сЃ╝сЃЅсѓњУ╝ЅсЂЏсЂдсЂёсЂЙсЂЎсЂїсђЂсЂёсЂЈсЂцсЂІТюфт«џуЙЕсЂфсѓѓсЂ«сЂїсЂѓсѓІсЂ«сЂДсђЂсЂЊсѓїсЂасЂЉсЂасЂесѓесЃЕсЃ╝сЂФсЂфсЂБсЂАсѓЃсЂёсЂЙсЂЎсђѓ status.lua local function GetHostAndCwd(elems, pane) local uri = pane:get_current_working_dir() if not uri then return end local cwd_uri = uri:sub(8) local slash = cwd_uri:find '/' if not slash then return end local host = cwd_uri:sub(1, slash - 1) local dot = host:find '[.]' AddElement(elems, HEADER_HOST, dot and host:sub(1, dot - 1) or host) AddElement(elems, HEADER_CWD, cwd_uri:sub(slash))
end local function GetDate(elems) AddElement(elems, HEADER_DATE, wezterm.strftime '%a %b %-d')
end local function GetTime(elems) AddElement(elems, HEADER_TIME, wezterm.strftime '%H:%M')
end local function GetBattery(elems, window) if not window:get_dimensions().is_full_screen then return end for _, b in ipairs(wezterm.battery_info()) do AddElement(elems, HEADER_BATTERY, string.format('%.0f%%', b.state_of_charge * 100)) end
end wez сЂЋсѓЊсЂ«сѓхсЃ│сЃЌсЃФсЂДсЂ»СИђт║дсЂФтЈќтЙЌсЂЌсЂдсЂёсЂЪdateсЂеtimeсѓѓтѕєсЂЉсЂАсѓЃсЂБсЂдсЂЙсЂЎсђѓ уеІт║дсЂ»тѕєсЂІсѓісЂЙсЂЏсѓЊсЂїсђЂжЮъті╣ујЄсЂДсЂ»сЂѓсѓІсЂеТђЮсѓЈсѓїсѓІсЂ«сЂДсЂітЦйсЂ┐сЂД­ЪўЅ сЃљсЃЃсЃєсЃфсЃ╝УАеуц║сЂФсЂцсЂёсЂдсЂ»сђЂсѓЈсЂЪсЂЌсЂ«та┤тљѕсЂ»сЃЋсЃФсѓ╣сѓ»сЃфсЃ╝сЃ│сЂ«ТЎѓсЂасЂЉтЄ║сЂЌсЂдсЂёсЂЙсЂЎсђѓсѓ╣сѓ»сЃфсЃ╝сЃ│уіХТЁІсЂ»СИІУеўсЂДтЈќтЙЌсЂДсЂЇсЂЙсЂЎсђѓ window:get_dimensions() The table has the following fields: pixel_width: the width of the window in pixels pixel_height: the height of the window in pixels dpi: The DPI of the screen the window in on is_full_screen: whether the window is in full screen mode сЃєсЃ╝сЃќсЃФсЂФсЂ»С╗ЦСИІсЂ«сЃЋсѓБсЃ╝сЃФсЃЅсЂїсЂѓсѓісЂЙсЂЎ: pixel_width: сЃћсѓ»сѓ╗сЃФтЇўСйЇсЂ«сѓдсѓБсЃ│сЃЅсѓдсЂ«т╣Ё pixel_height: сЃћсѓ»сѓ╗сЃФтЇўСйЇсЂДУАесЂЌсЂЪсѓдсѓБсЃ│сЃЅсѓдсЂ«жФўсЂЋ dpi: сѓдсѓБсЃ│сЃЅсѓдсЂїУАеуц║сЂЋсѓїсЂдсЂёсѓІсѓ╣сѓ»сЃфсЃ╝сЃ│сЂ« DPI is_full_screen: сѓдсѓБсЃ│сЃЅсѓдсЂїсЃЋсЃФсѓ╣сѓ»сЃфсЃ╝сЃ│сЃбсЃ╝сЃЅсЂДсЂѓсѓІсЂІсЂЕсЂєсЂІ сЂЊсЂЊсЂДсЂ»is_full_screenсѓњСй┐сЂёсЂЙсЂЎсђѓсЃЋсЃФсѓ╣сѓ»сЃфсЃ╝сЃ│ТЎѓсЂ»trueсЂїУ┐ћсѓісЂЙсЂЎсђѓ Note OSсЂІсѓЅсЂ«сЃЋсЃФсѓ╣сѓ»сЃфсЃ╝сЃ│ТЊЇСйюсђЂсѓѓсЂЌсЂЈсЂ» WezTermсЂ« ToggleFullScreen сЂФтЈЇт┐юсЂЌсЂЙсЂЎсђѓ (С╗ЦтЅЇсђЂToggleFullScreenсЂасЂетЈЇт┐юсЂЌсЂфсЂёсЂеТЏИсЂёсЂдсЂёсЂЙсЂЌсЂЪсЂїсђЂС╗іУдІсЂЪсѓЅсЂАсѓЃсѓЊсЂетІЋсЂёсЂдсЂЙсЂЌсЂЪРў║№ИЈ) сЂДсђЂС╗ЦСИІсЂїУХ│сѓісЂдсЂёсЂфсЂІсЂБсЂЪт«џуЙЕсЂДсЂЎсђѓ status.lua local HEADER_HOST = { Foreground = { Color = '#75b1a9' }, Text = '№Ѕг' }
local HEADER_CWD = { Foreground = { Color = '#92aac7' }, Text = '№Ђ╝' }
local HEADER_DATE = { Foreground = { Color = '#ffccac' }, Text = 'з▒ф║' }
local HEADER_TIME = { Foreground = { Color = '#bcbabe' }, Text = 'ЬЎЂ' }
local HEADER_BATTERY = { Foreground = { Color = '#dfe166' }, Text = '№ЅЂ' } local function AddElement(elems, header, str) table.insert(elems, { Foreground = header.Foreground }) table.insert(elems, { Background = DEFAULT_BG }) table.insert(elems, { Text = header.Text .. SPACE_1 }) table.insert(elems, { Foreground = DEFAULT_FG }) table.insert(elems, { Background = DEFAULT_BG }) table.insert(elems, { Text = str .. SPACE_3 })
end (тЅЇсЂ«сЃџсЃ╝сѓИсЂДТЏИсЂёсЂЪт«џуЙЕсѓѓСй┐ућесЂЌсЂдсЂёсѓІсЂ«сЂДсђЂуёАсЂІсЂБсЂЪсѓЅС╗ЦСИІсѓѓУ┐йУеўсЂЌсЂдсЂЈсЂасЂЋсЂёсђѓ) local DEFAULT_FG = { Color = '#9a9eab' }
local DEFAULT_BG = { Color = '#333333' } local SPACE_1 = ' '
local SPACE_3 = ' ' т╝ЋсЂБт╝хсЂБсЂЪтЅ▓сЂФсЂ»уЅ╣сЂФсѓ│сЃАсЃ│сЃѕсЂЎсѓІсЂесЂЊсѓЇсѓѓсЂфсЂёсЂДсЂЎсЂГ...сђѓсЂЮсЂ«сЂЙсЂЙт«їТѕљсЂЋсЂЏсЂАсѓЃсЂёсЂЙсЂЌсѓЄсЂє­Ъўі status.lua local function RightUpdate(window, pane) local elems = {} GetHostAndCwd(elems, pane) GetDate(elems) GetBattery(elems, window) GetTime(elems) window:set_right_status(wezterm.format(elems))
end wezterm.on('update-status', function(window, pane) LeftUpdate(window, pane) -- тЅЇтЏъТЏИсЂёсЂЪсѓ│сЃ╝сЃЅсЂ»сЂЮсЂ«сЂЙсЂЙсЂДсђѓ RightUpdate(window, pane)
end) сЂЋсЂдсђЂсЂЊсѓїсЂДсЂЊсѓЊсЂфТёЪсЂўсЂФсЂфсЂБсЂЪсЂ»сЂџсЂфсѓЊсЂДсЂЎсЂїсЂЕсЂєсЂДсЂЌсѓЄсЂєРЮЊ(СЙІсЂФсѓѕсЂБсЂдсЃдсЃ╝сѓХсЃ╝тљЇсЂ»жЏЉсЂФжџасЂЌсЂдсЂЙсЂЎсђѓ) сЃЋсЃФсѓ╣сѓ»сЃфсЃ╝сЃ│ТЎѓсЂФсЂ»сЃљсЃЃсЃєсЃфсЃ╝УАеуц║сЂїсЂЋсѓїсЂдсЂёсѓІсЂЊсЂесѓѓуб║УфЇсЂДсЂЇсЂЙсЂЎсђѓ Success УЈ»сѓёсЂІсЂФсЂфсѓісЂЙсЂЌсЂЪсЂГРў║№ИЈ (сЂЙсЂѓсђЂсЂХсЂБсЂАсѓЃсЂЉсЂЮсѓЊсЂфУдІсЂфсЂёсѓЊсЂасЂЉсЂЕ...) сѓхсЃ│сЃЌсЃФжђџсѓісЂесЂ»сЂёсЂѕсђЂУЄфтѕєсЂДТЏИсЂёсЂЪсѓ│сЃ╝сЃЅсЂїтІЋсЂЈсѓЊсЂасЂІсѓЅТЦйсЂЌсЂёСИќуЋїсЂДсЂЎсђѓсЂ╗сѓЈсЂ╗сѓЈсђю­ЪњЋ

